SELECT tab.id, tab.orderNo, tab.welfareCenterRewardType, tab.receiveStatus, tab.currencyCode, tab.amount, tab.detailType, tab.pfTime, tab.pfEndTime FROM (
SELECT id, order_no as orderNo, 1 AS welfareCenterRewardType, CASE WHEN receive_status = 0 AND receive_end_time < #{vo.systemTime} THEN 2 ELSE receive_status END AS receiveStatus, currency_code AS currencyCode, activity_amount AS amount, activity_template AS detailType, CASE WHEN receive_status = 0 AND receive_end_time < #{vo.systemTime} or receive_status = 2 THEN receive_end_time WHEN receive_status = 1 THEN receive_time ELSE created_time END AS pfTime, receive_end_time AS pfEndTime FROM site_activity_order_record_v2 WHERE site_code = #{vo.siteCode} AND show_flag = 1 AND user_account = #{vo.userAccount}
UNION ALL SELECT id, order_id as orderNo, 0 AS welfareCenterRewardType, CASE WHEN receive_status = 0 AND expired_time < #{vo.systemTime} THEN 2 ELSE receive_status END AS receiveStatus, currency AS currencyCode, award_amount AS amount, award_type AS detailType, IF ( receive_status = 1, receive_time, record_start_time ) AS pfTime, expired_time AS pfEndTime FROM site_vip_award_record_v2 WHERE site_code = #{vo.siteCode} AND user_account = #{vo.userAccount}
